// Function to detect the start index of the cycle in a linked list
int detectCycle(Node* head) {
    if (!head) return -1;

    Node* slow = head;
    Node* fast = head;

    // Step 1: Detect cycle
    while (fast && fast->next) {
        slow = slow->next;
        fast = fast->next->next;
        if (slow == fast)
            break;
    }

    if (!fast || !fast->next)
        return -1; // No cycle

    // Step 2: Find start of the cycle
    slow = head;
    int index = 0;
    while (slow != fast) {
        slow = slow->next;
        fast = fast->next;
        index++;
    }

    return index;
}

