    if (!head) return -1;

    let slow = head;
    let fast = head;

    // Step 1: Detect cycle
    while (fast && fast.next) {
        slow = slow.next;
        fast = fast.next.next;
        if (slow === fast) break;
    }

    if (!fast || !fast.next) return -1; // No cycle

    // Step 2: Find the start of the cycle
    slow = head;
    let index = 0;
    while (slow !== fast) {
        slow = slow.next;
        fast = fast.next;
        index++;
    }

    return index;
